import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';
import { FaEye, FaEyeSlash, FaUpload } from 'react-icons/fa';

const ProfilePage = () => {
  const { user, setUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [username, setUsername] = useState(user?.username || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [pic, setPic] = useState(null);
  const [preview, setPreview] = useState(null);
  const [curPw, setCurPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [showPw, setShowPw] = useState(false);
  const [toast, setToast] = useState({ msg: '', type: '' });
  const [darkMode, setDarkMode] = useState(false);

  /* ================= THEME ================= */
  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  /* ================= TOAST AUTO HIDE ================= */
  useEffect(() => {
    if (!toast.msg) return;
    const timer = setTimeout(() => setToast({ msg: '', type: '' }), 3000);
    return () => clearTimeout(timer);
  }, [toast]);

  /* ================= PASSWORD STRENGTH ================= */
  const getStrength = () => {
    if (!newPw) return "";
    if (newPw.length < 6) return "Weak";
    if (newPw.match(/^(?=.*[A-Z])(?=.*[0-9]).{6,}$/)) return "Strong";
    return "Medium";
  };

  const strength = getStrength();

  /* ================= HANDLERS ================= */
  const handleProfile = async (e) => {
    e.preventDefault();
    const fd = new FormData();
    fd.append('name', name);
    fd.append('bio', bio);
    fd.append('username', username);
    if (pic) fd.append('profilePic', pic);

    try {
      const { data } = await API.put('/auth/profile', fd);
      setUser(data);
      setToast({ msg: 'Profile updated!', type: 'success' });
    } catch (err) {
      setToast({ msg: err.response?.data?.message || 'Error updating profile', type: 'error' });
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    try {
      await API.put('/auth/change-password', {
        currentPassword: curPw,
        newPassword: newPw,
      });

      setToast({ msg: 'Password changed!', type: 'success' });
      setCurPw('');
      setNewPw('');
    } catch (err) {
      setToast({ msg: err.response?.data?.message || 'Error changing password', type: 'error' });
    }
  };

  const handleFileChange = (file) => {
    setPic(file);
    if (file) setPreview(URL.createObjectURL(file));
  };

  const picSrc = preview
    ? preview
    : user?.profilePic
    ? `http://localhost:5000/uploads/${user.profilePic}`
    : '/default-avatar.png';

  /* ================= STYLES ================= */
  const styles = {
    page: {
      background: darkMode ? "#560032" : "#FAE8ED",
      minHeight: '100vh',
      padding: '40px 20px',
      display: 'flex',
      justifyContent: 'center',
    },

    container: {
      width: '100%',
      maxWidth: '720px',
      backgroundColor: darkMode ? "#2e091e" : "#f7c6d9",
      padding: '30px',
      borderRadius: '20px',
      boxShadow: "0 10px 30px rgba(0,0,0,0.15)",
    },

    header: {
      textAlign: "center",
      marginBottom: "30px",
    },

    profilePic: {
      width: '120px',
      height: '120px',
      borderRadius: '50%',
      objectFit: 'cover',
      border: "3px solid white",
      marginBottom: "10px",
    },

    section: {
      background: darkMode ? "#381727" : "#fff",
      padding: "20px",
      borderRadius: "15px",
      marginBottom: "20px",
    },

    input: {
      width: "100%",
      padding: "12px",
      borderRadius: "10px",
      border: "1px solid #ccc",
      marginBottom: "12px",
    },

    textarea: {
      width: "100%",
      padding: "12px",
      borderRadius: "10px",
      border: "1px solid #ccc",
      marginBottom: "12px",
    },

    passwordRow: {
      position: "relative",
      marginBottom: "12px",
    },

    iconBtn: {
      position: "absolute",
      right: "10px",
      top: "50%",
      transform: "translateY(-50%)",
      cursor: "pointer",
      color: "#888",
    },

    fileBox: {
      display: "flex",
      alignItems: "center",
      gap: "10px",
      marginBottom: "10px",
    },

    uploadBtn: {
      display: "flex",
      alignItems: "center",
      gap: "5px",
      background: "#ddd",
      padding: "8px 12px",
      borderRadius: "8px",
      cursor: "pointer",
    },

    button: {
      marginTop: "10px",
      padding: "12px",
      borderRadius: "10px",
      border: "none",
      cursor: "pointer",
      fontWeight: "bold",
      backgroundColor: darkMode ? "#c46392" : "#0c4b34",
      color: "#fff",
      width: "100%",
    },

    toast: {
      position: "fixed",
      top: "20px",
      right: "20px",
      padding: "12px 18px",
      borderRadius: "10px",
      color: "#fff",
      backgroundColor: toast.type === "success" ? "#16a34a" : "#dc2626",
      animation: "slideIn 0.3s ease",
      zIndex: 999,
    },

    strength: {
      fontSize: "12px",
      marginBottom: "10px",
      color:
        strength === "Strong"
          ? "green"
          : strength === "Medium"
          ? "orange"
          : "red",
    },
  };

  return (
    <div style={styles.page}>
      {toast.msg && <div style={styles.toast}>{toast.msg}</div>}

      <div style={styles.container}>

        {/* HEADER */}
        <div style={styles.header}>
          <img src={picSrc} alt="Profile" style={styles.profilePic} />
          <p>@{user?.username}</p>
          <p>{user?.bio || "No bio yet."}</p>
        </div>

        {/* PROFILE */}
        <form style={styles.section} onSubmit={handleProfile}>
          <h3>Edit Profile</h3>

          <input value={name} onChange={(e) => setName(e.target.value)} placeholder="Display name" style={styles.input} />
          <input value={user?.email || ""} disabled style={styles.input} />
          <input value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Username" style={styles.input} />

          <textarea value={bio} onChange={(e) => setBio(e.target.value)} rows={3} style={styles.textarea} />

          <div style={styles.fileBox}>
            <label style={styles.uploadBtn}>
              <FaUpload /> Upload
              <input type="file" hidden onChange={(e) => handleFileChange(e.target.files[0])} />
            </label>
            <span>{pic ? pic.name : "No file selected"}</span>
          </div>

          <button type="submit" style={styles.button}>Save Profile</button>
        </form>

        {/* PASSWORD */}
        <form style={styles.section} onSubmit={handlePassword}>
          <h3>Change Password</h3>

          <div style={styles.passwordRow}>
            <input
              type={showPw ? "text" : "password"}
              placeholder="Current password"
              value={curPw}
              onChange={(e) => setCurPw(e.target.value)}
              style={styles.input}
            />
            <span style={styles.iconBtn} onClick={() => setShowPw(!showPw)}>
              {showPw ? <FaEyeSlash /> : <FaEye />}
            </span>
          </div>

          <div style={styles.passwordRow}>
            <input
              type={showPw ? "text" : "password"}
              placeholder="New password"
              value={newPw}
              onChange={(e) => setNewPw(e.target.value)}
              style={styles.input}
            />
          </div>

          {newPw && <div style={styles.strength}>Strength: {strength}</div>}

          <button type="submit" style={styles.button}>Change Password</button>
        </form>

      </div>
    </div>
  );
};

export default ProfilePage;
